module signal_generator(
    input clk,
    input rst_n,
    output [4:0] wave
);

reg [4:0] wave_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        wave_reg <= 5'b0;
    end else begin
        if (wave_reg == 5'd31) begin
            wave_reg <= 5'd30;
        end else if (wave_reg == 5'd0) begin
            wave_reg <= 5'd1;
        end else if (wave_reg[4] == 1'b0) begin
            wave_reg <= wave_reg + 1'b1;
        end else begin
            wave_reg <= wave_reg - 1'b1;
        end
    end
end

assign wave = wave_reg;

endmodule
